import sys


class Solution:
    def addStrings(self, num1: str, num2: str) -> str:
        n1, n2 = 0, 0
        num1, num2 = num1[::-1], num2[::-1]
        for i, j in enumerate(num1):
            n1 += int(j) * (10 ** i)
        for i, j in enumerate(num2):
            n2 += int(j) * (10 ** i)
        sys.set_int_max_str_digits(5001)
        return str(n1+n2)
c = Solution()
print(c.addStrings("1", ""))